using System;

namespace HP.OCI.Core.Services
{
    /// <summary>
    /// Pure domain service — no native interop.
    /// </summary>
    public sealed class OciQueryService
    {
        private readonly IOciRepository _repo;

        public OciQueryService(IOciRepository repo)
        {
            _repo = repo ?? throw new ArgumentNullException(nameof(repo));
        }

        public OciDevice GetDevice(string deviceId)
        {
            if (string.IsNullOrWhiteSpace(deviceId))
                throw new ArgumentException("deviceId must not be empty", nameof(deviceId));

            return _repo.FindById(deviceId)
                ?? throw new DeviceNotFoundException(deviceId);
        }
    }
}
